#include "heater_pwm.h"
#include <Arduino.h>
#define HEATER_PIN 25
static uint8_t _power=0;
void heater_setup(){ledcAttach(HEATER_PIN,1000,8);Serial.println("[heater] OK");}
void heater_set_power(uint8_t p){_power=constrain(p,0,100);ledcWrite(HEATER_PIN,map(_power,0,100,0,255));}
uint8_t heater_get_power(){return _power;}
void heater_off(){heater_set_power(0);}
